const sourceItem =
  $('invoice__trigger--subworkflow').first();

if (!sourceItem) {
  throw new Error('VALIDATION_SOURCE_INVOICE_NOT_FOUND');
}

const invoice = sourceItem.json;

const lookupItems = $input.all();

const vendorMatches = lookupItems
  .map(item => item.json)
  .filter(vendor => {
    return Boolean(
      vendor &&
      vendor.vendor_id &&
      vendor.vendor_tax_id
    );
  });

const normalizeText = (value) => {
  if (value === null || value === undefined) {
    return '';
  }

  return String(value)
    .replace(/\s+/g, ' ')
    .trim();
};

const normalizeUpper = (value) => {
  return normalizeText(value).toUpperCase();
};

const normalizeEmail = (value) => {
  return normalizeText(value).toLowerCase();
};

const normalizeBankCode = (value) => {
  return normalizeUpper(value)
    .replace(/[^A-Z0-9]/g, '');
};

const normalizeBoolean = (value) => {
  if (typeof value === 'boolean') {
    return value;
  }

  return [
    'true',
    '1',
    'yes',
    'active'
  ].includes(
    normalizeText(value).toLowerCase()
  );
};

const riskFlags = new Set(
  Array.isArray(invoice.risk_flags)
    ? invoice.risk_flags
    : []
);

let vendorFound = false;
let vendorRecordCount = vendorMatches.length;
let vendorRecord = null;

let vendorActive = false;
let senderEmailMatch = false;
let bankDetailsMatch = false;
let currencyMatch = false;
let vendorTaxIdMatch = false;

if (vendorRecordCount === 0) {
  riskFlags.add('vendor_not_found');
}

if (vendorRecordCount > 1) {
  riskFlags.add('vendor_tax_id_not_unique');
}

if (vendorRecordCount === 1) {
  vendorFound = true;
  vendorRecord = vendorMatches[0];

  vendorActive = normalizeBoolean(
    vendorRecord.is_active
  );

  vendorTaxIdMatch =
    normalizeUpper(invoice.vendor_tax_id) ===
    normalizeUpper(vendorRecord.vendor_tax_id);

  senderEmailMatch =
    normalizeEmail(invoice.sender_email) ===
    normalizeEmail(vendorRecord.contact_email);

  bankDetailsMatch =
    normalizeBankCode(invoice.iban) ===
    normalizeBankCode(vendorRecord.iban);

  currencyMatch =
    normalizeUpper(invoice.currency) ===
    normalizeUpper(vendorRecord.default_currency);

  if (!vendorActive) {
    riskFlags.add('vendor_inactive');
  }

  if (!vendorTaxIdMatch) {
    riskFlags.add('vendor_tax_id_mismatch');
  }

  if (!senderEmailMatch) {
    riskFlags.add('sender_email_mismatch');
  }

  if (!bankDetailsMatch) {
    riskFlags.add('iban_mismatch');
  }

  if (!currencyMatch) {
    riskFlags.add('currency_mismatch');
  }
}

const criticalVendorFlags = [
  'vendor_not_found',
  'vendor_tax_id_not_unique',
  'vendor_inactive',
  'vendor_tax_id_mismatch',
  'sender_email_mismatch',
  'iban_mismatch'
];

const normalizedRiskFlags = [...riskFlags]
  .filter(Boolean)
  .sort();

const requiresManualReview =
  normalizedRiskFlags.some(flag =>
    criticalVendorFlags.includes(flag)
  );

return [
  {
    json: {
      ...invoice,

      status: 'vendor_validated',

      vendor_found: vendorFound,
      vendor_record_count: vendorRecordCount,
      vendor_id:
        vendorRecord?.vendor_id ?? null,
      vendor_active: vendorActive,

      vendor_tax_id_match: vendorTaxIdMatch,
      sender_email_match: senderEmailMatch,
      bank_details_match: bankDetailsMatch,
      currency_match: currencyMatch,

      registered_vendor_name:
        vendorRecord?.vendor_name ?? null,
      registered_contact_email:
        vendorRecord?.contact_email ?? null,
      registered_iban:
        vendorRecord?.iban ?? null,
      registered_currency:
        vendorRecord?.default_currency ?? null,

      manager_id:
        vendorRecord?.manager_id ??
        invoice.manager_id ??
        '',

      risk_flags: normalizedRiskFlags,
      requires_manual_review: requiresManualReview,

      vendor_validated_at:
        new Date().toISOString()
    },

    binary: sourceItem.binary
  }
];

const sourceItem =
  $('invoice__vendor--validate-record').first();

if (!sourceItem) {
  throw new Error('DUPLICATE_SOURCE_INVOICE_NOT_FOUND');
}

const invoice = sourceItem.json;

const lookupRows = $input.all()
  .map(item => item.json)
  .filter(row => {
    return Boolean(
      row &&
      row.invoice_id
    );
  });

const normalizeText = (value) => {
  if (value === null || value === undefined) {
    return '';
  }

  return String(value)
    .replace(/\s+/g, ' ')
    .trim();
};

const normalizeUpper = (value) => {
  return normalizeText(value).toUpperCase();
};

const normalizeAmount = (value) => {
  if (
    value === null ||
    value === undefined ||
    value === ''
  ) {
    return null;
  }

  const normalized = String(value)
    .replace(/\s/g, '')
    .replace(/,/g, '');

  const number = Number(normalized);

  return Number.isFinite(number)
    ? Math.round(number * 100) / 100
    : null;
};

const currentProcessingId =
  normalizeText(invoice.processing_id);

const currentInvoiceId =
  normalizeUpper(invoice.invoice_id);

const currentAmount =
  normalizeAmount(invoice.total_amount);

const duplicateRows = lookupRows.filter(row => {
  const rowInvoiceId =
    normalizeUpper(row.invoice_id);

  const rowProcessingId =
    normalizeText(row.processing_id);

  return (
    rowInvoiceId === currentInvoiceId &&
    rowProcessingId !== currentProcessingId
  );
});

const exactDuplicateRows = [];
const amountMismatchRows = [];

for (const row of duplicateRows) {
  const existingAmount =
    normalizeAmount(row.total_amount);

  if (
    currentAmount !== null &&
    existingAmount !== null &&
    Math.abs(currentAmount - existingAmount) <= 0.01
  ) {
    exactDuplicateRows.push(row);
  } else {
    amountMismatchRows.push(row);
  }
}

const riskFlags = new Set(
  Array.isArray(invoice.risk_flags)
    ? invoice.risk_flags
    : []
);

if (exactDuplicateRows.length > 0) {
  riskFlags.add('duplicate_invoice');
}

if (amountMismatchRows.length > 0) {
  riskFlags.add(
    'invoice_number_reused_amount_mismatch'
  );
}

const isDuplicate =
  duplicateRows.length > 0;

const normalizedRiskFlags = [...riskFlags]
  .filter(Boolean)
  .sort();

const requiresManualReview =
  Boolean(invoice.requires_manual_review) ||
  isDuplicate;

return [
  {
    json: {
      ...invoice,

      status: 'duplicate_validated',

      is_duplicate: isDuplicate,
      duplicate_record_count:
        duplicateRows.length,
      exact_duplicate_count:
        exactDuplicateRows.length,
      amount_mismatch_count:
        amountMismatchRows.length,

      duplicate_processing_ids:
        duplicateRows
          .map(row => row.processing_id)
          .filter(Boolean),

      duplicate_drive_urls:
        duplicateRows
          .map(row => row.drive_file_url)
          .filter(Boolean),

      risk_flags: normalizedRiskFlags,
      requires_manual_review:
        requiresManualReview,

      duplicate_validated_at:
        new Date().toISOString()
    },

    binary: sourceItem.binary
  }
];

const invoice = $json;

const normalizeArray = (value) => {
  if (!Array.isArray(value)) {
    return [];
  }

  return [...new Set(
    value
      .map(item => String(item).trim())
      .filter(Boolean)
  )].sort();
};

const riskFlags = normalizeArray(
  invoice.risk_flags
);

const missingFields = normalizeArray(
  invoice.missing_fields
);

const structuralFlags = [
  'invalid_invoice_date',
  'invalid_due_date',
  'due_date_before_invoice_date',
  'invalid_total_amount',
  'invalid_currency',
  'invalid_iban_format',
  'total_amount_mismatch',
  'low_extraction_confidence'
];

const manualReviewFlags = [
  'vendor_not_found',
  'vendor_tax_id_not_unique',
  'vendor_inactive',
  'vendor_tax_id_mismatch',
  'sender_email_mismatch',
  'iban_mismatch',
  'duplicate_invoice',
  'invoice_number_reused_amount_mismatch'
];

const warningFlags = [
  'currency_mismatch'
];

const hasStructuralProblem =
  invoice.extraction_valid === false ||
  missingFields.length > 0 ||
  riskFlags.some(flag =>
    structuralFlags.includes(flag)
  );

const hasManualReviewProblem =
  Boolean(invoice.requires_manual_review) ||
  riskFlags.some(flag =>
    manualReviewFlags.includes(flag)
  );

const hasWarning =
  riskFlags.some(flag =>
    warningFlags.includes(flag)
  );

let validationResult = 'valid';
let status = 'validated';

if (hasStructuralProblem) {
  validationResult = 'invalid';
  status = 'validation_failed';
} else if (hasManualReviewProblem) {
  validationResult = 'manual_review';
  status = 'manual_review';
} else if (hasWarning || riskFlags.length > 0) {
  validationResult = 'warning';
  status = 'validation_warning';
}

const parseIsoDate = (value) => {
  if (
    typeof value !== 'string' ||
    !/^\d{4}-\d{2}-\d{2}$/.test(value)
  ) {
    return null;
  }

  const date = new Date(`${value}T00:00:00Z`);

  return Number.isNaN(date.getTime())
    ? null
    : date;
};

const dueDate = parseIsoDate(
  invoice.due_date
);

const now = new Date();

const todayUtc = new Date(
  Date.UTC(
    now.getUTCFullYear(),
    now.getUTCMonth(),
    now.getUTCDate()
  )
);

let isOverdue = false;
let daysUntilDue = null;

if (dueDate) {
  const differenceMs =
    dueDate.getTime() - todayUtc.getTime();

  daysUntilDue = Math.ceil(
    differenceMs / 86400000
  );

  isOverdue = daysUntilDue < 0;
}

if (isOverdue) {
  if (!riskFlags.includes('invoice_overdue')) {
    riskFlags.push('invoice_overdue');
    riskFlags.sort();
  }

  if (validationResult === 'valid') {
    validationResult = 'warning';
    status = 'validation_warning';
  }
}

const validationSummary = {
  extraction_valid:
    Boolean(invoice.extraction_valid),
  vendor_found:
    Boolean(invoice.vendor_found),
  vendor_active:
    Boolean(invoice.vendor_active),
  sender_email_match:
    Boolean(invoice.sender_email_match),
  bank_details_match:
    Boolean(invoice.bank_details_match),
  currency_match:
    Boolean(invoice.currency_match),
  is_duplicate:
    Boolean(invoice.is_duplicate),
  is_overdue: isOverdue
};

return {
  json: {
    ...invoice,

    status,
    validation_result: validationResult,

    risk_flags: riskFlags,
    missing_fields: missingFields,

    is_overdue: isOverdue,
    days_until_due: daysUntilDue,

    requires_manual_review:
      validationResult === 'manual_review',

    validation_summary:
      validationSummary,

    validated_at:
      new Date().toISOString()
  },

  binary: $binary
};

const validationItem =
  $('invoice__validation--finalize-result').item;

if (!validationItem) {
  throw new Error('FINAL_VALIDATION_RESULT_NOT_FOUND');
}

return {
  json: {
    ...validationItem.json,

    registry_updated: true,
    registry_row_number:
      $json.row_number ??
      $json.rowNumber ??
      null,

    validation_workflow_completed_at:
      new Date().toISOString()
  },

  binary: validationItem.binary
};
